package main

import (
	"bufio"
	"fmt"
	"os"
)

func substituir(texto, alvo, subs string) string {
    var textoalt []byte
    i := 0
    for i < len(texto) {
        encontrou := true
        if i+len(alvo) <= len(texto) {
            for j := 0; j < len(alvo); j++ {
                if texto[i+j] != alvo[j] {
                    encontrou = false
                    break
                }
            }
        } else {
            encontrou = false
        }
        if encontrou {
            for j := 0; j < len(subs); j++ {
                textoalt = append(textoalt, subs[j])
            }
            i += len(alvo)
        } else {
        textoalt = append(textoalt, texto[i])
        i++
    }
}
    return string(textoalt)
}

func main() {
    texto := ""
    alvo := ""
    subs := ""
    Scanner := bufio.NewScanner(os.Stdin)
    Scanner.Scan()
    texto = Scanner.Text()
    Scanner.Scan()
    alvo = Scanner.Text()
    Scanner.Scan()
    subs = Scanner.Text()
    frase := substituir(texto,alvo,subs)
    fmt.Println(frase)
}
